--
-- Intro to Postgres - Series 03 Sample Data
--
-- This file creates and populates tables for learning SQL JOINs:
-- - INNER JOIN (users + posts, users + user_preferences)
-- - LEFT JOIN (customers + orders, users + posts with orphans)
-- - UNION (current_employees + former_employees)
--
-- Usage: Run this file in any SQL client (TablePlus, pgAdmin, etc.)
--

-- Clean up if tables exist (in correct order due to foreign keys)
DROP TABLE IF EXISTS orders CASCADE;
DROP TABLE IF EXISTS posts CASCADE;
DROP TABLE IF EXISTS user_preferences CASCADE;
DROP TABLE IF EXISTS customers CASCADE;
DROP TABLE IF EXISTS users CASCADE;
DROP TABLE IF EXISTS current_employees CASCADE;
DROP TABLE IF EXISTS former_employees CASCADE;

--
-- Users table
--

CREATE TABLE users (
    id bigint NOT NULL,
    name character varying(255) NOT NULL,
    email character varying(255) NOT NULL,
    created_at timestamp(0) without time zone DEFAULT CURRENT_TIMESTAMP,
    updated_at timestamp(0) without time zone DEFAULT CURRENT_TIMESTAMP
);

CREATE SEQUENCE users_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1;
ALTER SEQUENCE users_id_seq OWNED BY users.id;
ALTER TABLE ONLY users ALTER COLUMN id SET DEFAULT nextval('users_id_seq'::regclass);

--
-- User preferences table (1:1 with users)
--

CREATE TABLE user_preferences (
    user_id bigint NOT NULL,
    theme text DEFAULT 'light',
    notifications_enabled boolean DEFAULT true,
    updated_at timestamp(0) without time zone DEFAULT CURRENT_TIMESTAMP
);

--
-- Posts table (many:1 with users)
--

CREATE TABLE posts (
    id bigint NOT NULL,
    title character varying(255) NOT NULL,
    content text NOT NULL,
    user_id bigint,
    published boolean DEFAULT false,
    view_count integer DEFAULT 0,
    created_at timestamp(0) without time zone DEFAULT CURRENT_TIMESTAMP,
    updated_at timestamp(0) without time zone DEFAULT CURRENT_TIMESTAMP
);

CREATE SEQUENCE posts_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1;
ALTER SEQUENCE posts_id_seq OWNED BY posts.id;
ALTER TABLE ONLY posts ALTER COLUMN id SET DEFAULT nextval('posts_id_seq'::regclass);

--
-- Customers table
--

CREATE TABLE customers (
    id bigint NOT NULL,
    email character varying(255) NOT NULL,
    created_at timestamp(0) without time zone DEFAULT CURRENT_TIMESTAMP,
    updated_at timestamp(0) without time zone DEFAULT CURRENT_TIMESTAMP
);

CREATE SEQUENCE customers_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1;
ALTER SEQUENCE customers_id_seq OWNED BY customers.id;
ALTER TABLE ONLY customers ALTER COLUMN id SET DEFAULT nextval('customers_id_seq'::regclass);

--
-- Orders table (many:1 with customers)
--

CREATE TABLE orders (
    id bigint NOT NULL,
    customer_id bigint NOT NULL,
    total numeric(10,2) NOT NULL,
    created_at timestamp(0) without time zone DEFAULT CURRENT_TIMESTAMP,
    updated_at timestamp(0) without time zone DEFAULT CURRENT_TIMESTAMP
);

CREATE SEQUENCE orders_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1;
ALTER SEQUENCE orders_id_seq OWNED BY orders.id;
ALTER TABLE ONLY orders ALTER COLUMN id SET DEFAULT nextval('orders_id_seq'::regclass);

--
-- Current employees table (for UNION demos)
--

CREATE TABLE current_employees (
    id bigint NOT NULL,
    name character varying(255) NOT NULL,
    email character varying(255) NOT NULL,
    department character varying(255) NOT NULL,
    hire_date date NOT NULL,
    created_at timestamp(0) without time zone DEFAULT CURRENT_TIMESTAMP,
    updated_at timestamp(0) without time zone DEFAULT CURRENT_TIMESTAMP
);

CREATE SEQUENCE current_employees_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1;
ALTER SEQUENCE current_employees_id_seq OWNED BY current_employees.id;
ALTER TABLE ONLY current_employees ALTER COLUMN id SET DEFAULT nextval('current_employees_id_seq'::regclass);

--
-- Former employees table (for UNION demos)
--

CREATE TABLE former_employees (
    id bigint NOT NULL,
    name character varying(255) NOT NULL,
    email character varying(255) NOT NULL,
    department character varying(255) NOT NULL,
    created_at timestamp(0) without time zone DEFAULT CURRENT_TIMESTAMP,
    updated_at timestamp(0) without time zone DEFAULT CURRENT_TIMESTAMP
);

CREATE SEQUENCE former_employees_id_seq START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1;
ALTER SEQUENCE former_employees_id_seq OWNED BY current_employees.id;
ALTER TABLE ONLY former_employees ALTER COLUMN id SET DEFAULT nextval('former_employees_id_seq'::regclass);

