--
-- Update sequences
--

SELECT setval('users_id_seq', (SELECT MAX(id) FROM users), true);
SELECT setval('posts_id_seq', (SELECT MAX(id) FROM posts), true);
SELECT setval('customers_id_seq', (SELECT MAX(id) FROM customers), true);
SELECT setval('orders_id_seq', (SELECT MAX(id) FROM orders), true);
SELECT setval('current_employees_id_seq', (SELECT MAX(id) FROM current_employees), true);
SELECT setval('former_employees_id_seq', (SELECT MAX(id) FROM former_employees), true);

--
-- Primary keys
--

ALTER TABLE ONLY users ADD CONSTRAINT users_pkey PRIMARY KEY (id);
ALTER TABLE ONLY user_preferences ADD CONSTRAINT user_preferences_pkey PRIMARY KEY (user_id);
ALTER TABLE ONLY posts ADD CONSTRAINT posts_pkey PRIMARY KEY (id);
ALTER TABLE ONLY customers ADD CONSTRAINT customers_pkey PRIMARY KEY (id);
ALTER TABLE ONLY orders ADD CONSTRAINT orders_pkey PRIMARY KEY (id);
ALTER TABLE ONLY current_employees ADD CONSTRAINT current_employees_pkey PRIMARY KEY (id);
ALTER TABLE ONLY former_employees ADD CONSTRAINT former_employees_pkey PRIMARY KEY (id);

--
-- Unique constraints
--

ALTER TABLE ONLY users ADD CONSTRAINT users_email_unique UNIQUE (email);
ALTER TABLE ONLY customers ADD CONSTRAINT customers_email_unique UNIQUE (email);
ALTER TABLE ONLY current_employees ADD CONSTRAINT current_employees_email_unique UNIQUE (email);
ALTER TABLE ONLY former_employees ADD CONSTRAINT former_employees_email_unique UNIQUE (email);

--
-- Foreign keys
--

ALTER TABLE ONLY user_preferences ADD CONSTRAINT user_preferences_user_id_foreign FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE;
ALTER TABLE ONLY posts ADD CONSTRAINT posts_user_id_foreign FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE SET NULL;
ALTER TABLE ONLY orders ADD CONSTRAINT orders_customer_id_foreign FOREIGN KEY (customer_id) REFERENCES customers(id) ON DELETE CASCADE;
